INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation)
VALUES
('4908c859-6a7f-4135-b5fc-308e33281ce9', 'Tiêu chí ''Fluency'' (Sự trôi chảy) trong IELTS Speaking được đánh giá dựa trên yếu tố nào?', 'multiple_choice', '["Nói cực kỳ nhanh không kịp thở.","Không bao giờ được dừng lại.","Khả năng duy trì nhịp độ nói đều đặn, ngắt nghỉ đúng chỗ (Chunking) và giảm thiểu tối đa các khoảng ngập ngừng ngắc ngứ (Hesitation) liên quan đến việc tìm từ vựng/ngữ pháp.","Chỉ nói những câu đơn giản."]', 'Khả năng duy trì nhịp độ nói đều đặn, ngắt nghỉ đúng chỗ (Chunking) và giảm thiểu tối đa các khoảng ngập ngừng ngắc ngứ (Hesitation) liên quan đến việc tìm từ vựng/ngữ pháp.', 'Sự trôi chảy không phải là Tốc độ (Speed). Nói chậm nhưng nhịp điệu mượt mà, ngắt nghỉ đúng cụm nghĩa sẽ đạt điểm Fluency cao hơn nói nhanh mà bị vấp liên tục.'),
('4908c859-6a7f-4135-b5fc-308e33281ce9', 'Việc sử dụng các ''Fillers'' (Từ chêm) như ''Well'', ''You know'', ''Actually'' có làm bạn bị trừ điểm không?', 'multiple_choice', '["Có, sẽ bị trừ điểm rất nặng.","Không, nếu được sử dụng một cách tự nhiên và vừa phải để giữ lượt lời, chúng giúp ngôn ngữ nói trở nên chân thực như người bản xứ.","Tùy thuộc vào giám khảo.","Có, vì nó là ngôn ngữ bất lịch sự."]', 'Không, nếu được sử dụng một cách tự nhiên và vừa phải để giữ lượt lời, chúng giúp ngôn ngữ nói trở nên chân thực như người bản xứ.', 'Tuy nhiên, lạm dụng (Overuse) từ chêm ở mọi câu, ví dụ ''like, you know, ummm'' sẽ làm giảm điểm trôi chảy vì nó chứng tỏ bạn đang chật vật tìm từ.'),
('4908c859-6a7f-4135-b5fc-308e33281ce9', 'Hành động ''Self-correction'' (Tự sửa lỗi ngữ pháp trong lúc nói) có ảnh hưởng thế nào đến điểm số?', 'multiple_choice', '["Tự sửa lỗi luôn làm tăng điểm ngữ pháp.","Nếu thỉnh thoảng tự sửa lỗi nhỏ, điều đó không sao. Nhưng nếu bạn liên tục vấp và tự sửa lỗi (over-correction), điểm Fluency của bạn sẽ bị kéo xuống nghiêm trọng.","Tự sửa lỗi khiến bạn bị hủy bài thi.","Tự sửa lỗi không ảnh hưởng gì."]', 'Nếu thỉnh thoảng tự sửa lỗi nhỏ, điều đó không sao. Nhưng nếu bạn liên tục vấp và tự sửa lỗi (over-correction), điểm Fluency của bạn sẽ bị kéo xuống nghiêm trọng.', 'Trong văn nói, đôi khi việc bỏ qua một lỗi ngữ pháp nhỏ để duy trì luồng giao tiếp trôi chảy lại tốt hơn là cứ ngập ngừng sửa đi sửa lại.'),
('b13b2176-9521-40bd-bb92-12fa0d321ace', 'Tiêu chí ''Pronunciation'' (Phát âm) trong IELTS Speaking KHÔNG đánh giá điều gì?', 'multiple_choice', '["Ngữ điệu (Intonation) và Trọng âm (Stress).","Việc bạn có giọng (Accent) giống hệt người Anh hay người Mỹ hay không.","Sự phát âm rõ ràng các âm cuối (Ending sounds).","Việc ngắt nghỉ cụm từ (Chunking)."]', 'Việc bạn có giọng (Accent) giống hệt người Anh hay người Mỹ hay không.', 'IELTS chấp nhận mọi loại Accent (giọng địa phương) miễn là phát âm của bạn rõ ràng, có ngữ điệu tốt và không gây cản trở cho việc nghe hiểu (Intelligibility).'),
('b13b2176-9521-40bd-bb92-12fa0d321ace', 'Nếu bạn không nghe rõ câu hỏi của giám khảo, bạn nên làm gì?', 'multiple_choice', '["Im lặng đoán mò câu hỏi và trả lời lạc đề.","Lịch sự yêu cầu giám khảo lặp lại câu hỏi: ''Sorry, I didn''t quite catch that. Could you repeat the question, please?''.","Hỏi giám khảo bằng tiếng Việt.","Nói ''Pass'' để chuyển câu hỏi."]', 'Lịch sự yêu cầu giám khảo lặp lại câu hỏi: ''Sorry, I didn''t quite catch that. Could you repeat the question, please?''.', 'Việc yêu cầu lặp lại (ở Part 1 và 3) hoàn toàn không bị trừ điểm. Nó thể hiện kỹ năng giao tiếp tự nhiên khi gặp sự cố.'),
('b13b2176-9521-40bd-bb92-12fa0d321ace', 'Giám khảo thường xuyên ngắt lời (Interrupt) bạn trong lúc nói. Điều này có nghĩa là gì?', 'multiple_choice', '["Bạn đang nói rất tệ và họ muốn kết thúc sớm.","Đó là quy trình kiểm soát thời gian bình thường của bài thi; họ cần ngắt bạn để chuyển sang câu hỏi khác nhằm đảm bảo đủ thời lượng cho toàn bộ bài test.","Bạn đã làm họ tức giận.","Họ đang buồn ngủ."]', 'Đó là quy trình kiểm soát thời gian bình thường của bài thi; họ cần ngắt bạn để chuyển sang câu hỏi khác nhằm đảm bảo đủ thời lượng cho toàn bộ bài test.', 'Đừng hoảng sợ khi bị ngắt lời. Điều đó thậm chí có thể là tín hiệu tốt cho thấy bạn nói quá trôi chảy và cung cấp đủ thông tin nên họ không cần nghe thêm.'),
('629eff7b-fd56-44d8-adcd-fb82576b6e4d', 'Thuật ngữ ''Tertiary education'' (hoặc Higher education) chỉ cấp bậc học nào?', 'multiple_choice', '["Mẫu giáo.","Cấp 3 (Trung học phổ thông).","Giáo dục Đại học và Sau đại học.","Giáo dục nghề nghiệp tại nhà."]', 'Giáo dục Đại học và Sau đại học.', '''Tertiary education'' là từ vựng C1 thay thế hoàn hảo cho cụm ''University education'' trong các bài luận về giáo dục.'),
('629eff7b-fd56-44d8-adcd-fb82576b6e4d', 'Khái niệm ''Curriculum'' trong trường học có nghĩa là gì?', 'multiple_choice', '["Thời khóa biểu hàng ngày.","Chương trình học, bao gồm tất cả các môn học và nội dung được giảng dạy trong một cơ sở giáo dục.","Quy định về đồng phục.","Khuôn viên trường học."]', 'Chương trình học, bao gồm tất cả các môn học và nội dung được giảng dạy trong một cơ sở giáo dục.', 'Ví dụ: ''Extracurricular activities'' (Hoạt động ngoại khóa) là những hoạt động nằm ngoài cái ''curriculum'' này.'),
('629eff7b-fd56-44d8-adcd-fb82576b6e4d', 'Từ ''Literacy rate'' dùng để chỉ tỷ lệ gì trong một quốc gia?', 'multiple_choice', '["Tỷ lệ thất nghiệp.","Tỷ lệ sinh đẻ.","Tỷ lệ người biết chữ (biết đọc và biết viết).","Tỷ lệ tội phạm."]', 'Tỷ lệ người biết chữ (biết đọc và biết viết).', 'Ngược lại, ''Illiteracy'' (nạn mù chữ) là một chủ đề lớn trong các bài thảo luận về các quốc gia đang phát triển.'),
('11d2f539-9b7e-4cf4-9e11-1918c6dcc781', 'Collocation ''Sedentary lifestyle'' ám chỉ một lối sống như thế nào, thường dẫn đến các vấn đề sức khỏe?', 'multiple_choice', '["Lối sống ăn chay trường.","Lối sống thụ động, ngồi nhiều, thiếu vận động thể chất.","Lối sống thích mạo hiểm.","Lối sống luôn di chuyển, du lịch."]', 'Lối sống thụ động, ngồi nhiều, thiếu vận động thể chất.', 'Đây là nguyên nhân số một được trích dẫn khi phân tích tình trạng ''Obesity'' (béo phì) trong xã hội hiện đại.'),
('11d2f539-9b7e-4cf4-9e11-1918c6dcc781', 'Thuật ngữ ''Preventative medicine'' (Y tế dự phòng) có mục đích gì?', 'multiple_choice', '["Chữa trị cho người đã mắc bệnh nan y.","Ngăn ngừa bệnh tật xảy ra ngay từ đầu thông qua tiêm chủng, khám định kỳ và lối sống lành mạnh.","Sản xuất các thiết bị phẫu thuật.","Nghiên cứu về các bệnh trong quá khứ."]', 'Ngăn ngừa bệnh tật xảy ra ngay từ đầu thông qua tiêm chủng, khám định kỳ và lối sống lành mạnh.', 'Trong IELTS, thường có sự so sánh giữa ''Preventative medicine'' (phòng bệnh) và ''Curative medicine'' (chữa bệnh).'),
('11d2f539-9b7e-4cf4-9e11-1918c6dcc781', 'Sự lây lan nhanh chóng của một căn bệnh truyền nhiễm trong một khu vực lớn hoặc trên toàn thế giới được gọi là gì?', 'multiple_choice', '["Allergy (Dị ứng).","Epidemic / Pandemic (Dịch bệnh / Đại dịch).","Injury (Chấn thương).","Syndrome (Hội chứng)."]', 'Epidemic / Pandemic (Dịch bệnh / Đại dịch).', 'Epidemic là dịch bệnh khu vực; Pandemic là đại dịch quy mô toàn cầu (như Covid-19).'),
('d26f5a65-d27d-4ce1-b08a-a2225d91f1d1', 'Khái niệm ''Carbon footprint'' (Dấu chân carbon) đo lường điều gì?', 'multiple_choice', '["Kích thước bánh xe của phương tiện.","Tổng lượng khí nhà kính (chủ yếu là CO2) mà các hành động của một cá nhân, tổ chức hoặc quốc gia thải ra môi trường.","Số lượng cây cối được trồng lại.","Diện tích của một khu rừng bị cháy."]', 'Tổng lượng khí nhà kính (chủ yếu là CO2) mà các hành động của một cá nhân, tổ chức hoặc quốc gia thải ra môi trường.', 'Để bảo vệ môi trường, con người cần phải ''reduce their carbon footprint'' (giảm thiểu dấu chân carbon).'),
('d26f5a65-d27d-4ce1-b08a-a2225d91f1d1', 'Các nguồn năng lượng như Mặt trời, Gió, Nước được gọi chung bằng thuật ngữ gì?', 'multiple_choice', '["Fossil fuels (Nhiên liệu hóa thạch).","Renewable energy (Năng lượng tái tạo).","Nuclear power (Năng lượng hạt nhân).","Toxic waste (Chất thải độc hại)."]', 'Renewable energy (Năng lượng tái tạo).', 'Năng lượng tái tạo (Renewable energy) không thể bị cạn kiệt, trái ngược với Nhiên liệu hóa thạch (Fossil fuels) như than đá và dầu mỏ.'),
('d26f5a65-d27d-4ce1-b08a-a2225d91f1d1', 'Sự tuyệt chủng của nhiều loài động vật (Extinction) thường có nguyên nhân chính từ hành động nào của con người?', 'multiple_choice', '["Habitat destruction (Phá hủy môi trường sống tự nhiên).","Animal feeding (Cho động vật ăn).","Building zoos (Xây dựng sở thú).","Taking photographs (Chụp ảnh động vật)."]', 'Habitat destruction (Phá hủy môi trường sống tự nhiên).', 'Việc tàn phá rừng (deforestation) và đô thị hóa dẫn đến mất đi môi trường sống (habitat loss) là đòn chí mạng đối với đa dạng sinh học.'),
('4ea309f8-59d5-4071-9310-78e3e99d2f37', 'Tính từ ''Obsolete'' được dùng để miêu tả một công nghệ như thế nào?', 'multiple_choice', '["Đang là xu hướng mới nhất.","Lỗi thời, cổ hủ, không còn được sử dụng nữa vì đã bị thay thế bởi công nghệ mới hơn.","Đắt đỏ nhất.","Khó sử dụng."]', 'Lỗi thời, cổ hủ, không còn được sử dụng nữa vì đã bị thay thế bởi công nghệ mới hơn.', 'Ví dụ: ''Typewriters have become obsolete'' (Máy đánh chữ đã trở nên lỗi thời).'),
('4ea309f8-59d5-4071-9310-78e3e99d2f37', 'Ngược lại với Obsolete, thuật ngữ nào miêu tả những công nghệ tiên tiến nhất, hiện đại nhất hiện nay?', 'multiple_choice', '["Second-hand.","Cutting-edge / State-of-the-art.","Traditional.","Analog."]', 'Cutting-edge / State-of-the-art.', 'Đây là 2 tính từ ghép cấp độ C1 rất hay dùng trong Writing và Speaking khi miêu tả công nghệ mới.'),
('4ea309f8-59d5-4071-9310-78e3e99d2f37', 'Khái niệm ''Artificial Intelligence'' (AI) đề cập đến điều gì?', 'multiple_choice', '["Những con robot đồ chơi.","Trí tuệ nhân tạo: khả năng của máy móc có thể mô phỏng tư duy, học hỏi và giải quyết vấn đề giống như bộ não con người.","Mạng lưới kết nối internet toàn cầu.","Một loại virus máy tính."]', 'Trí tuệ nhân tạo: khả năng của máy móc có thể mô phỏng tư duy, học hỏi và giải quyết vấn đề giống như bộ não con người.', 'AI là một trong những Mega-trends (siêu xu hướng) xuất hiện liên tục trong đề thi IELTS gần đây.');